// removeDuplicates.cpp
#include <iostream>
#include <vector>

namespace Solution {
void removeDuplicates(std::vector<int>& nums) {
 int n = nums.size(); if (n <= 1) return;
 for (int i = 1; i < n - 1; i++) {
  if (nums[i] == nums[i - 1]) nums[i] = nums[i + 1];
 }
}
}

int main() {
 std::vector<int> nums = {1, 1, 2, 2, 2, 3, 4, 5, 5, 5};
 Solution::removeDuplicates(nums);
 for (auto num : nums) std::cout << num << " ";
 return 0;
}

